#!/usr/bin/env node
/**
 * GHL API Skill Module
 * Provides GoHighLevel operations for OpenClaw agents
 * 
 * Usage: node ghl-api.mjs <command> [args...]
 * 
 * Commands:
 *   get-contact <contactId>               Get contact details
 *   list-tasks <contactId> [limit]        List contact tasks
 *   search-contacts <query>               Search contacts
 *   create-contact <json>                 Create new contact
 *   create-task <contactId> <json>        Create contact task
 *   ensure-task <contactId> <json> [prefix]  Create task only if no matching open task exists
 *   update-contact <contactId> <json>     Update contact
 *   add-tag <contactId> <tag>             Add tag to contact
 *   remove-tag <contactId> <tag>          Remove tag from contact
 *   move-stage <opportunityId> <stageId>  Move opportunity to stage
 *   send-sms <contactId> <message>        Send SMS to contact
 *   send-email <contactId> <subject> <body>  Send email to contact
 *   get-opportunities [pipelineId]        List opportunities
 *   get-conversations <contactId>         Get conversation history
 *   calculate-lead-score <contactId>      Calculate lead score
 */

import { readFileSync, writeFileSync } from 'fs';
import { join } from 'path';

const GHL_TOKEN = process.env.GHL_PRIVATE_INTEGRATION_TOKEN || process.env.GHL_PRIVATE_INTEGRATION_TOKEN_TJB || process.env.GHL_TOKEN || '';
const GHL_LOCATION = process.env.GHL_LOCATION_ID || 'TW8JsPW5NMnA3tfK2XLn';
const GHL_BASE = 'https://services.leadconnectorhq.com';
const API_VERSION = '2021-07-28';

const headers = {
  'Authorization': `Bearer ${GHL_TOKEN}`,
  'Version': API_VERSION,
  'Accept': 'application/json',
  'Content-Type': 'application/json'
};

// Rate limit: minimum spacing between GHL API calls (ms)
const MIN_CALL_SPACING_MS = 3000;
let lastCallAt = 0;

const DLQ_PATH = join(process.env.USERPROFILE || process.env.HOME || '', '.openclaw', 'data', 'dead-letter-queue.json');

function logToDLQ(entry) {
  try {
    const dlq = JSON.parse(readFileSync(DLQ_PATH, 'utf-8'));
    dlq.entries.push(entry);
    dlq.totalProcessed++;
    dlq.lastUpdated = new Date().toISOString();
    writeFileSync(DLQ_PATH, JSON.stringify(dlq, null, 2) + '\n', 'utf-8');
  } catch {
    // DLQ write failure is non-fatal
  }
}

function parseResponseBody(text) {
  if (!text) {
    return null;
  }

  try {
    return JSON.parse(text);
  } catch {
    return { raw: text };
  }
}

function buildQuery(params) {
  const query = new URLSearchParams();

  for (const [key, value] of Object.entries(params)) {
    if (value === undefined || value === null || value === '') {
      continue;
    }
    query.set(key, String(value));
  }

  const serialized = query.toString();
  return serialized ? `?${serialized}` : '';
}

function normalizeTaskList(data) {
  if (Array.isArray(data)) {
    return data;
  }

  if (Array.isArray(data?.tasks)) {
    return data.tasks;
  }

  if (Array.isArray(data?.data?.tasks)) {
    return data.data.tasks;
  }

  if (Array.isArray(data?.data)) {
    return data.data;
  }

  if (Array.isArray(data?.contacts)) {
    return data.contacts;
  }

  return [];
}

function normalizeTaskText(value) {
  return String(value || '')
    .normalize('NFKC')
    .replace(/[\u2012-\u2015]/g, '-')
    .replace(/[^\p{L}\p{N}]+/gu, ' ')
    .trim()
    .toLowerCase();
}

function getTaskTitle(task) {
  return String(task?.title || task?.name || task?.subject || '').trim();
}

function getTaskBody(task) {
  return String(task?.body || task?.description || task?.notes || '').trim();
}

function matchesTaskDedupe(task, { titlePrefix, bodyIncludes } = {}) {
  if (isTaskCompleted(task)) {
    return false;
  }

  const normalizedTitle = normalizeTaskText(getTaskTitle(task));
  const normalizedBody = normalizeTaskText(getTaskBody(task));
  const normalizedPrefix = normalizeTaskText(titlePrefix);
  const normalizedBodyIncludes = normalizeTaskText(bodyIncludes);

  if (normalizedPrefix && normalizedTitle.startsWith(normalizedPrefix)) {
    return true;
  }

  if (normalizedBodyIncludes && normalizedBody.includes(normalizedBodyIncludes)) {
    return true;
  }

  return false;
}

function isTaskCompleted(task) {
  if (typeof task?.completed === 'boolean') {
    return task.completed;
  }

  const status = String(task?.status || '').toLowerCase();
  return status === 'completed' || status === 'done' || status === 'closed';
}

function buildTaskPayload(taskData = {}) {
  const title = String(taskData.title || '').trim();
  const body = String(taskData.body || '').trim();
  const dueDate = taskData.dueDate ? new Date(taskData.dueDate).toISOString() : new Date(Date.now() + 60 * 60 * 1000).toISOString();

  if (!title) {
    throw new Error('Task title is required');
  }

  if (!body) {
    throw new Error('Task body is required');
  }

  return {
    title,
    body,
    dueDate,
    completed: Boolean(taskData.completed ?? false)
  };
}

async function apiCall(method, endpoint, body = null, _retryCount = 0) {
  // Enforce minimum spacing between calls
  const elapsed = Date.now() - lastCallAt;
  if (elapsed < MIN_CALL_SPACING_MS) {
    await new Promise(r => setTimeout(r, MIN_CALL_SPACING_MS - elapsed));
  }
  lastCallAt = Date.now();

  const url = `${GHL_BASE}${endpoint}`;
  const options = { method, headers };
  if (body) {
    options.body = JSON.stringify(body);
  }
  
  const response = await fetch(url, options);

  // Auth expired — do not retry, log to DLQ
  if (response.status === 401 || response.status === 403) {
    const msg = `GHL auth expired (${response.status}) on ${method} ${endpoint}`;
    logToDLQ({ type: 'ghl-auth-expired', message: msg, timestamp: new Date().toISOString(), endpoint });
    throw new Error(msg);
  }

  // Rate limited — retry with backoff (max 2 retries)
  if (response.status === 429 && _retryCount < 2) {
    const retryAfter = parseInt(response.headers.get('retry-after') || '10', 10);
    const delay = (retryAfter * 1000) + Math.random() * 2000;
    console.warn(`GHL 429 rate limited, retrying in ${Math.ceil(delay)}ms (attempt ${_retryCount + 1}/2)`);
    await new Promise(r => setTimeout(r, delay));
    return apiCall(method, endpoint, body, _retryCount + 1);
  }

  const rawText = await response.text();
  const data = parseResponseBody(rawText);
  
  if (!response.ok) {
    const msg = `GHL API Error ${response.status}: ${JSON.stringify(data)}`;
    if (response.status === 429) {
      logToDLQ({ type: 'ghl-rate-limit', message: msg, timestamp: new Date().toISOString(), endpoint });
    }
    throw new Error(msg);
  }
  
  return data;
}

// ============ Contact Operations ============

async function getContact(contactId) {
  return apiCall('GET', `/contacts/${contactId}`);
}

async function searchContacts(query) {
  return apiCall('GET', `/contacts/?locationId=${GHL_LOCATION}&query=${encodeURIComponent(query)}`);
}

async function createContact(contactData) {
  return apiCall('POST', '/contacts/', {
    ...contactData,
    locationId: GHL_LOCATION
  });
}

async function updateContact(contactId, updates) {
  return apiCall('PUT', `/contacts/${contactId}`, updates);
}

async function addTag(contactId, tag) {
  return apiCall('POST', `/contacts/${contactId}/tags`, { tags: [tag] });
}

async function removeTag(contactId, tag) {
  return apiCall('DELETE', `/contacts/${contactId}/tags`, { tags: [tag] });
}

async function listTasks(contactId, limit = 100) {
  const query = buildQuery({ locationId: GHL_LOCATION, limit });
  return apiCall('GET', `/contacts/${contactId}/tasks${query}`);
}

async function createTask(contactId, taskData) {
  return apiCall('POST', `/contacts/${contactId}/tasks`, buildTaskPayload(taskData));
}

async function ensureTask(contactId, taskData, dedupePrefix = null) {
  const payload = buildTaskPayload(taskData);
  const existingResponse = await listTasks(contactId, 100);
  const tasks = normalizeTaskList(existingResponse);

  const existingTask = tasks.find((task) => matchesTaskDedupe(task, {
    titlePrefix: dedupePrefix || payload.title,
    bodyIncludes: payload.body
  }));

  if (existingTask) {
    return {
      created: false,
      task: existingTask
    };
  }

  const createdTask = await createTask(contactId, payload);
  return {
    created: true,
    task: createdTask?.task || createdTask
  };
}

// ============ Pipeline Operations ============

async function getOpportunities(pipelineId = null) {
  let endpoint = `/opportunities/?locationId=${GHL_LOCATION}`;
  if (pipelineId) {
    endpoint += `&pipelineId=${pipelineId}`;
  }
  return apiCall('GET', endpoint);
}

async function moveStage(opportunityId, stageId) {
  return apiCall('PUT', `/opportunities/${opportunityId}`, {
    stageId
  });
}

// ============ Messaging Operations ============

async function sendSMS(contactId, message) {
  return apiCall('POST', '/conversations/messages', {
    type: 'SMS',
    contactId,
    message
  });
}

async function sendEmail(contactId, subject, body) {
  return apiCall('POST', '/conversations/messages', {
    type: 'Email',
    contactId,
    subject,
    message: body
  });
}

async function getConversations(contactId) {
  return apiCall('GET', `/conversations/?locationId=${GHL_LOCATION}&contactId=${contactId}`);
}

// ============ Lead Scoring ============

async function calculateLeadScore(contactId) {
  const contact = await getContact(contactId);
  const conversations = await getConversations(contactId);
  
  let score = 0;
  
  // Response speed (0-20 pts)
  // If responded within 24h, full points
  const firstResponse = conversations.conversations?.[0];
  if (firstResponse) {
    const responseTime = Date.now() - new Date(firstResponse.dateAdded).getTime();
    const hoursToRespond = responseTime / (1000 * 60 * 60);
    if (hoursToRespond < 1) score += 20;
    else if (hoursToRespond < 24) score += 15;
    else if (hoursToRespond < 72) score += 10;
    else score += 5;
  }
  
  // Email engagement (0-20 pts)
  const contact_data = contact.contact || contact;
  if (contact_data.emailVerified) score += 10;
  const emailOpens = contact_data.customFields?.email_opens || 0;
  score += Math.min(emailOpens * 2, 10);
  
  // SMS replies (0-20 pts)
  const smsReplies = conversations.conversations?.filter(c => c.type === 'SMS' && c.direction === 'inbound').length || 0;
  score += Math.min(smsReplies * 5, 20);
  
  // Alignment score from scorecard (0-20 pts)
  const alignmentScore = contact_data.customFields?.alignment_score || 0;
  score += Math.round((alignmentScore / 100) * 20);
  
  // Form completions (0-20 pts)
  const tags = contact_data.tags || [];
  if (tags.includes('scorecard-lead')) score += 10;
  if (tags.includes('ebook-buyer')) score += 10;
  
  return {
    contactId,
    score: Math.min(score, 100),
    breakdown: {
      responseSpeed: Math.min(20, score),
      emailEngagement: 10,
      smsReplies: Math.min(smsReplies * 5, 20),
      alignmentScore: Math.round((alignmentScore / 100) * 20),
      formCompletions: (tags.includes('scorecard-lead') ? 10 : 0) + (tags.includes('ebook-buyer') ? 10 : 0)
    }
  };
}

// ============ CLI Handler ============

async function main() {
  const [,, command, ...args] = process.argv;
  
  if (!command) {
    console.log('Usage: node ghl-api.mjs <command> [args...]');
    console.log('Commands: get-contact, search-contacts, create-contact, update-contact,');
    console.log('          add-tag, remove-tag, list-tasks, create-task, ensure-task,');
    console.log('          move-stage, send-sms, send-email,');
    console.log('          get-opportunities, get-conversations, calculate-lead-score');
    process.exit(1);
  }
  
  try {
    if (!GHL_TOKEN) {
      throw new Error('Missing GHL token. Set GHL_PRIVATE_INTEGRATION_TOKEN, GHL_PRIVATE_INTEGRATION_TOKEN_TJB, or GHL_TOKEN.');
    }

    let result;
    
    switch (command) {
      case 'get-contact':
        result = await getContact(args[0]);
        break;
      case 'list-tasks':
        result = await listTasks(args[0], Number(args[1] || 100));
        break;
      case 'search-contacts':
        result = await searchContacts(args[0]);
        break;
      case 'create-contact':
        result = await createContact(JSON.parse(args[0]));
        break;
      case 'create-task':
        result = await createTask(args[0], JSON.parse(args[1]));
        break;
      case 'ensure-task':
        result = await ensureTask(args[0], JSON.parse(args[1]), args[2]);
        break;
      case 'update-contact':
        result = await updateContact(args[0], JSON.parse(args[1]));
        break;
      case 'add-tag':
        result = await addTag(args[0], args[1]);
        break;
      case 'remove-tag':
        result = await removeTag(args[0], args[1]);
        break;
      case 'move-stage':
        result = await moveStage(args[0], args[1]);
        break;
      case 'send-sms':
        result = await sendSMS(args[0], args.slice(1).join(' '));
        break;
      case 'send-email':
        result = await sendEmail(args[0], args[1], args.slice(2).join(' '));
        break;
      case 'get-opportunities':
        result = await getOpportunities(args[0]);
        break;
      case 'get-conversations':
        result = await getConversations(args[0]);
        break;
      case 'calculate-lead-score':
        result = await calculateLeadScore(args[0]);
        break;
      default:
        console.error(`Unknown command: ${command}`);
        process.exit(1);
    }
    
    console.log(JSON.stringify(result, null, 2));
  } catch (error) {
    console.error('Error:', error.message);
    process.exit(1);
  }
}

main();

#!/usr/bin/env node
/**
 * Sales Pre-Call Briefing Generator
 * Generates comprehensive briefings before sales calls/appointments
 * 
 * Usage: node briefing-generator.mjs <contactId>
 * 
 * Output: Markdown briefing document with all relevant context
 */

const GHL_TOKEN = process.env.GHL_PRIVATE_INTEGRATION_TOKEN || 'pit-13ec5dbf-2508-41ff-af52-4698b7d6ef9a';
const GHL_LOCATION = process.env.GHL_LOCATION_ID || 'TW8JsPW5NMnA3tfK2XLn';
const GHL_BASE = 'https://services.leadconnectorhq.com';
const API_VERSION = '2021-07-28';

const headers = {
  'Authorization': `Bearer ${GHL_TOKEN}`,
  'Version': API_VERSION,
  'Content-Type': 'application/json'
};

async function apiCall(endpoint) {
  const response = await fetch(`${GHL_BASE}${endpoint}`, { headers });
  return response.json();
}

function formatDate(dateStr) {
  if (!dateStr) return 'N/A';
  return new Date(dateStr).toLocaleDateString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit'
  });
}

function getAlignmentTier(score) {
  if (score >= 90) return '🌟 Transcendent';
  if (score >= 75) return '⚡ Empowered';
  if (score >= 60) return '🎯 Aligned';
  if (score >= 40) return '🌱 Awakening';
  return '💤 Dormant';
}

function getLeadTemperature(score) {
  if (score >= 90) return '🔥 HOT';
  if (score >= 70) return '🌡️ WARM';
  if (score >= 50) return '❄️ COOL';
  return '🧊 COLD';
}

async function generateBriefing(contactId) {
  // Fetch all data in parallel
  const [contactRes, conversationsRes, opportunitiesRes] = await Promise.all([
    apiCall(`/contacts/${contactId}`),
    apiCall(`/conversations/?locationId=${GHL_LOCATION}&contactId=${contactId}`),
    apiCall(`/opportunities/?locationId=${GHL_LOCATION}&contactId=${contactId}`)
  ]);
  
  const contact = contactRes.contact || contactRes;
  const conversations = conversationsRes.conversations || [];
  const opportunities = opportunitiesRes.opportunities || [];
  
  // Extract custom fields
  const cf = contact.customFields || {};
  const alignmentScore = cf.alignment_score || 0;
  const leadScore = cf.lead_score || 0;
  const valueLadderStep = cf.value_ladder_step || 'unknown';
  const membershipStatus = cf.membership_status || 'none';
  
  // Analyze conversation history
  const smsCount = conversations.filter(c => c.type === 'SMS').length;
  const emailCount = conversations.filter(c => c.type === 'Email').length;
  const lastMessage = conversations[0];
  const inboundMessages = conversations.filter(c => c.direction === 'inbound');
  
  // Find active opportunity
  const activeOpp = opportunities.find(o => o.status === 'open') || opportunities[0];
  
  // Calculate engagement signals
  const daysSinceContact = lastMessage 
    ? Math.floor((Date.now() - new Date(lastMessage.dateAdded).getTime()) / (1000 * 60 * 60 * 24))
    : 999;
  
  const engagementLevel = inboundMessages.length >= 5 ? 'HIGH' 
    : inboundMessages.length >= 2 ? 'MEDIUM' 
    : 'LOW';
  
  // Build the briefing
  const briefing = `
# 📋 Pre-Call Briefing: ${contact.firstName} ${contact.lastName || ''}

**Generated:** ${new Date().toLocaleString()}
**Call Type:** ${activeOpp?.name || 'Discovery Call'}

---

## 👤 Contact Overview

| Field | Value |
|-------|-------|
| **Name** | ${contact.firstName} ${contact.lastName || ''} |
| **Email** | ${contact.email || 'N/A'} |
| **Phone** | ${contact.phone || 'N/A'} |
| **Location** | ${contact.city || ''}, ${contact.state || ''} ${contact.country || ''} |
| **Created** | ${formatDate(contact.dateAdded)} |
| **Source** | ${contact.source || 'Unknown'} |

---

## 📊 Scoring & Qualification

| Metric | Value | Interpretation |
|--------|-------|----------------|
| **Alignment Score** | ${alignmentScore}/100 | ${getAlignmentTier(alignmentScore)} |
| **Lead Score** | ${leadScore}/100 | ${getLeadTemperature(leadScore)} |
| **Value Ladder Position** | ${valueLadderStep} | - |
| **Membership Status** | ${membershipStatus} | - |
| **Engagement Level** | ${engagementLevel} | ${inboundMessages.length} inbound messages |

---

## 🏷️ Tags & Segments

${(contact.tags || []).map(t => `\`${t}\``).join(' ') || '_No tags_'}

---

## 💬 Communication History

- **Total Conversations:** ${conversations.length}
- **SMS Exchanges:** ${smsCount}
- **Email Threads:** ${emailCount}
- **Days Since Last Contact:** ${daysSinceContact}
- **Last Message:** ${lastMessage ? formatDate(lastMessage.dateAdded) : 'Never'}

### Recent Messages (Last 5)
${conversations.slice(0, 5).map(msg => `
**${msg.direction === 'inbound' ? '📥' : '📤'} ${formatDate(msg.dateAdded)}** (${msg.type})
> ${(msg.body || msg.message || '').substring(0, 200)}${(msg.body || msg.message || '').length > 200 ? '...' : ''}
`).join('\n') || '_No conversation history_'}

---

## 🎯 Pipeline Status

${activeOpp ? `
| Field | Value |
|-------|-------|
| **Pipeline** | ${activeOpp.pipelineName || 'Default'} |
| **Stage** | ${activeOpp.stageName || activeOpp.stageId} |
| **Value** | $${activeOpp.monetaryValue || 0} |
| **Created** | ${formatDate(activeOpp.createdAt)} |
| **Status** | ${activeOpp.status} |
` : '_No active opportunity_'}

---

## 🎙️ Talking Points

### Personalization Hooks
${alignmentScore >= 80 ? '- ✅ **High Alignment:** They understand the vision. Focus on implementation speed.' : ''}
${alignmentScore < 50 ? '- ⚠️ **Low Alignment:** May need more foundational education before selling.' : ''}
${contact.tags?.includes('ebook-buyer') ? '- 📚 Already bought eBook - reference it, ask what they learned.' : ''}
${contact.tags?.includes('hot-lead') ? '- 🔥 **Hot Lead:** Move fast, they are ready to buy.' : ''}
${daysSinceContact > 7 ? '- ⏰ Been a while since last contact - reconnect warmly first.' : ''}
${engagementLevel === 'HIGH' ? '- 💪 Highly engaged - they want this, just need the right offer.' : ''}

### Recommended Offer
${leadScore >= 90 && valueLadderStep !== 'coaching_applied' ? '**Primary:** Implementation Intensive ($997-$2,497) - They are ready for high-ticket.' : ''}
${leadScore >= 70 && leadScore < 90 ? '**Primary:** Agentic AI Mastery Course ($297) - Solid candidate for core offer.' : ''}
${leadScore >= 50 && leadScore < 70 ? '**Primary:** eBook + Prompt Vault bundle ($36.95) - Need more nurturing.' : ''}
${leadScore < 50 ? '**Primary:** Free value content - Not ready for paid offers yet.' : ''}

### Objection Handlers Ready
1. **"I don't have time"** → "The system saves 10+ hours/week. What would you do with that time?"
2. **"Too expensive"** → "What's the cost of NOT having AI agents? How much time are you losing?"
3. **"I'm not technical"** → "Neither were 80% of our students. That's exactly why we built this framework."
4. **"Need to think about it"** → "Totally understand. What specific questions do you need answered?"

---

## ⚠️ Red Flags

${contact.tags?.includes('do-not-contact') ? '🚫 **DO NOT CONTACT tag present!**' : ''}
${conversations.some(c => c.body?.toLowerCase().includes('refund')) ? '⚠️ Has mentioned refund in past conversations.' : ''}
${conversations.some(c => c.body?.toLowerCase().includes('unsubscribe')) ? '⚠️ Has requested to unsubscribe previously.' : ''}
${daysSinceContact > 30 ? '⚠️ No contact in 30+ days - may have gone cold.' : ''}
${engagementLevel === 'LOW' && smsCount > 5 ? '⚠️ Low response rate despite multiple outreach attempts.' : ''}

---

## ✅ Call Objectives

1. [ ] Build rapport and reconnect
2. [ ] Confirm their current situation and goals
3. [ ] Present appropriate offer based on qualification
4. [ ] Handle objections
5. [ ] Get commitment or schedule follow-up
6. [ ] Update pipeline stage after call

---

*Briefing generated by OpenClaw Sales Agent*
`;

  return briefing;
}

async function main() {
  const contactId = process.argv[2];
  
  if (!contactId) {
    console.error('Usage: node briefing-generator.mjs <contactId>');
    process.exit(1);
  }
  
  try {
    const briefing = await generateBriefing(contactId);
    console.log(briefing);
  } catch (error) {
    console.error('Error generating briefing:', error.message);
    process.exit(1);
  }
}

main();

